#!/bin/bash
set -e
echo "Deploying dashboard files..."
python3 -c "import base64; open('/opt/predictivEdge/server.js','wb').write(base64.b64decode(''))"
python3 -c "import base64; open('/opt/predictivEdge/public/index.html','wb').write(base64.b64decode(''))"
python3 -c "import base64; open('/opt/predictivEdge/public/script.js','wb').write(base64.b64decode(''))"
python3 -c "import base64; open('/opt/predictivEdge/public/style.css','wb').write(base64.b64decode(''))"
echo "Files written. Lines:"
wc -l /opt/predictivEdge/server.js /opt/predictivEdge/public/index.html /opt/predictivEdge/public/script.js /opt/predictivEdge/public/style.css
pm2 restart predictivEdge
echo "Done! Dashboard restarted."